if(session_status()===PHP_SESSION_NONE)session_start();if(empty($_SESSION['is_logged_in'])){header('Location: ../connexion.php');exit;}if(($_SESSION['user_type']??'')!=='agriculteur'){header('Location: dashboard.php');exit;}
require_once __DIR__.'/../models/select/PaiementSelect.php';$user_id=(int)$_SESSION['user_id'];$user_type='agriculteur';$user_nom=$_SESSION['user_nom']??'';$user_prenom=$_SESSION['user_prenom']??'';$user_email=$_SESSION['user_email']??'';$paiements=PaiementSelect::getByAgriculteur($user_id);$stats=['total'=>count($paiements),'attente'=>0,'payes'=>0,'revenu'=>0];foreach($paiements as $p){if($p->date_paiement){$stats['payes']++;$stats['revenu']+=(float)$p->montant_agriculteur;}else $stats['attente']++;}
?><!doctype html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Paiements - Butembo Marché</title><link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.2/dist/css/bootstrap.min.css" rel="stylesheet"><link href="https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.1/font/bootstrap-icons.css" rel="stylesheet"><style>
:root{--green:#2d6a4f;--bg:#f5f7f6;--surface:#fff;--text:#17202a;--muted:#64748b;--border:#e2e8f0;--soft:#f8fafc}html.dark{--bg:#0f172a;--surface:#1e293b;--text:#e2e8f0;--muted:#94a3b8;--border:#334155;--soft:#0f172a}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font-family:Inter,system-ui,sans-serif}.layout{display:flex;min-height:100vh}.sidebar{position:fixed;inset:0 auto 0 0;width:260px;background:var(--surface);border-right:1px solid var(--border);padding:24px 16px;display:flex;flex-direction:column}.brand{font-weight:800;color:var(--green);font-size:1.15rem;padding:0 12px 24px}.sidebar-nav{display:flex;flex-direction:column;gap:6px}.nav-label{padding:12px;color:#94a3b8;font-size:.72rem;text-transform:uppercase;font-weight:700}.nav-link{padding:11px 13px;border-radius:10px;color:var(--muted);text-decoration:none}.nav-link i{margin-right:9px}.nav-link:hover,.nav-link.active{background:var(--green);color:#fff}.profile{margin-top:auto;padding:16px 8px 0;border-top:1px solid var(--border)}.profile small,.profile strong{display:block}.profile small{color:var(--muted)}.main{margin-left:260px;width:calc(100% - 260px);padding:28px}.top{display:flex;justify-content:space-between;align-items:center}.stats{display:grid;grid-template-columns:repeat(4,1fr);gap:16px;margin:24px 0}.stat,.panel{background:var(--surface);border:1px solid var(--border);border-radius:14px;padding:20px}.stat strong{display:block;font-size:1.6rem}.muted,.stat span{color:var(--muted)}.payment{border:1px solid var(--border);padding:18px;border-radius:12px;margin-bottom:14px}.payment-head{display:flex;justify-content:space-between}.grid{display:grid;grid-template-columns:repeat(4,1fr);gap:14px;margin:15px 0}.label{font-size:.72rem;text-transform:uppercase;color:#94a3b8;font-weight:700}.products{background:var(--soft);padding:11px;border-radius:9px}.status{padding:6px 10px;border-radius:20px;font-size:.78rem;font-weight:700}.paid{background:#dcfce7;color:#166534}.pending{background:#fef3c7;color:#92400e}.overlay{position:fixed;inset:0;z-index:1050;background:#0f172a99;display:grid;place-items:center;padding:16px;opacity:0;visibility:hidden;transition:.2s}.overlay.active{opacity:1;visibility:visible}.modal-box{background:var(--surface);border:1px solid var(--border);border-radius:16px;padding:25px;width:100%;max-width:430px}.modal-actions{display:flex;justify-content:flex-end;gap:9px;margin-top:20px}@media(max-width:850px){.sidebar{position:static;width:100%}.layout{display:block}.main{margin:0;width:100%;padding:16px}.stats,.grid{grid-template-columns:1fr 1fr}}@media(max-width:520px){.stats,.grid{grid-template-columns:1fr}}
</style></head><body><div class="layout"><aside class="sidebar"><div class="brand"><i class="bi bi-basket2-fill"></i> Butembo Marché</div><?php require __DIR__.'/partials/sidebar-nav.php';?><div class="profile"><strong><?=htmlspecialchars($user_prenom.' '.$user_nom)?></strong><small><?=htmlspecialchars($user_email)?></small><a href="../models/logout.php" class="btn btn-sm btn-outline-danger mt-3">Déconnexion</a></div></aside><main class="main"><header class="top"><div><h1 class="h3 mb-1">Paiements</h1><p class="muted mb-0">Paiements des commandes de vos produits</p></div><button class="btn btn-outline-secondary" onclick="toggleTheme()"><i id="themeIcon" class="bi bi-moon-stars"></i></button></header><section class="stats"><div class="stat"><strong><?=$stats['total']?></strong><span>Total</span></div><div class="stat"><strong><?=$stats['attente']?></strong><span>En attente</span></div><div class="stat"><strong><?=$stats['payes']?></strong><span>Confirmés</span></div><div class="stat"><strong><?=number_format($stats['revenu'],0,',',' ')?> FC</strong><span>Revenus confirmés</span></div></section><section class="panel"><div id="message"></div><?php if(!$paiements):?><div class="text-center muted py-5"><i class="bi bi-wallet2 fs-1 d-block"></i>Aucun paiement disponible.</div><?php endif;?><?php foreach($paiements as $p):?><article class="payment"><div class="payment-head"><div><strong><?=htmlspecialchars($p->reference_paiement)?></strong><div class="muted small">Commande #<?=htmlspecialchars($p->numero_commande)?></div></div><span class="status <?=$p->date_paiement?'paid':'pending'?>"><?=$p->date_paiement?'Payé':'En attente'?></span></div><div class="grid"><div><div class="label">Votre montant</div><strong><?=number_format((float)$p->montant_agriculteur,0,',',' ')?> FC</strong></div><div><div class="label">Client</div><strong><?=htmlspecialchars($p->client_prenom.' '.$p->client_nom)?></strong></div><div><div class="label">Mode</div><strong><?=htmlspecialchars(str_replace('_',' ',$p->mode_paiement))?></strong></div><div><div class="label">Date</div><strong><?=$p->date_paiement?date('d/m/Y H:i',strtotime($p->date_paiement)):'Non payé'?></strong></div></div><div class="products mb-3"><?=htmlspecialchars(str_replace('||',' • ',$p->produits?:''))?></div><?php if(!$p->date_paiement):?><button class="btn btn-success" onclick="openConfirm(<?=(int)$p->id?>,'<?=htmlspecialchars($p->reference_paiement,ENT_QUOTES,'UTF-8')?>')"><i class="bi bi-check-circle me-1"></i>Confirmer le paiement</button><?php endif;?></article><?php endforeach;?></section></main></div>
<div class="overlay" id="confirmModal"><div class="modal-box"><h3 class="h5">Confirmer le paiement</h3><p class="muted" id="confirmText"></p><div class="modal-actions"><button class="btn btn-light" onclick="closeConfirm()">Annuler</button><button class="btn btn-success" id="confirmButton" onclick="submitPayment()">Confirmer</button></div></div></div><script>let paymentId=null;function openConfirm(id,ref){paymentId=id;document.getElementById('confirmText').textContent='Confirmez-vous la réception du paiement '+ref+' ?';document.getElementById('confirmModal').classList.add('active')}function closeConfirm(){document.getElementById('confirmModal').classList.remove('active');paymentId=null}async function submitPayment(){if(!paymentId)return;const b=document.getElementById('confirmButton');b.disabled=true;try{const r=await fetch('../models/traitement/paiements-post.php',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'confirm',id:paymentId})});const x=await r.json();if(!x.success)throw new Error(x.message);closeConfirm();document.getElementById('message').innerHTML='<div class="alert alert-success">'+x.message+'</div>';setTimeout(()=>location.reload(),700)}catch(e){closeConfirm();document.getElementById('message').innerHTML='<div class="alert alert-danger">'+e.message+'</div>';b.disabled=false}}function themeIcon(){document.getElementById('themeIcon').className=document.documentElement.classList.contains('dark')?'bi bi-sun':'bi bi-moon-stars'}function toggleTheme(){document.documentElement.classList.toggle('dark');localStorage.setItem('theme',document.documentElement.classList.contains('dark')?'dark':'light');themeIcon()}if(localStorage.getItem('theme')==='dark')document.documentElement.classList.add('dark');themeIcon()</script></body></html>
